import{_ as i,c as o,o as t,a5 as r,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.10: Major Stability Upgrade","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.10.md","filePath":"en/changelog/v1.1.10.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.10.md"};function s(l,a,d,p,h,c){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="v1-1-10-major-stability-upgrade" tabindex="-1">v1.1.10: Major Stability Upgrade <a class="header-anchor" href="#v1-1-10-major-stability-upgrade" aria-label="Permalink to “v1.1.10: Major Stability Upgrade”">​</a></h1><p><strong>Release Date</strong>: January 9, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update focuses on <strong>stability and experience optimization</strong>, fixing forked session loss, configuration errors failing silently, and making the desktop app better.</p><hr><h2 id="important-fix-configuration-errors-no-longer-fail-silently" tabindex="-1">Important Fix: Configuration Errors No Longer Fail Silently <a class="header-anchor" href="#important-fix-configuration-errors-no-longer-fail-silently" aria-label="Permalink to “Important Fix: Configuration Errors No Longer Fail Silently”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>If your configuration file (<code>settings.json</code>) had syntax errors, OpenCode would <strong>exit directly</strong> without telling you what&#39;s wrong. Many users thought it was a software bug, but actually the configuration was written incorrectly.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Now OpenCode <strong>clearly reports configuration errors</strong>, telling you exactly what went wrong, making it easy to fix quickly.</p><hr><h2 id="important-fix-forked-sessions-no-longer-lost" tabindex="-1">Important Fix: Forked Sessions No Longer Lost <a class="header-anchor" href="#important-fix-forked-sessions-no-longer-lost" aria-label="Permalink to “Important Fix: Forked Sessions No Longer Lost”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using the &quot;fork session&quot; feature (starting a new conversation from a message), if the session had been compacted, the forked session might <strong>lose messages</strong> or display abnormally.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Fixed parent-child message references, forked sessions now work properly.</p><p>👉 <strong>Related Tutorial</strong>: <a href="/en/5-advanced/20-compaction.html">Context Compaction</a></p><hr><h2 id="improvement-plugin-deduplication-mechanism" tabindex="-1">Improvement: Plugin Deduplication Mechanism <a class="header-anchor" href="#improvement-plugin-deduplication-mechanism" aria-label="Permalink to “Improvement: Plugin Deduplication Mechanism”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>If you configure multiple plugins with the same name (e.g., same plugin in both global and project configuration), OpenCode now <strong>automatically deduplicates by priority</strong>, avoiding duplicate loading.</p><p><strong>Priority Rule</strong>: Project configuration &gt; Global configuration</p><hr><h2 id="desktop-app-improvements" tabindex="-1">Desktop App Improvements <a class="header-anchor" href="#desktop-app-improvements" aria-label="Permalink to “Desktop App Improvements”">​</a></h2><p>This desktop version has many experience optimizations:</p><table tabindex="0"><thead><tr><th>Improvement</th><th>Description</th></tr></thead><tbody><tr><td>Terminal cursor optimization</td><td>Cursor changed to vertical bar style, stops blinking when unfocused</td></tr><tr><td>Zen mode fix</td><td>Model selector no longer overflows in new session</td></tr><tr><td>Symlink support</td><td>Full symlink support, convenient for monorepo projects</td></tr><tr><td>Terminal/review panel memory</td><td>Each session independently remembers panel display state</td></tr></tbody></table><hr><h2 id="bedrock-users-api-key-login" tabindex="-1">Bedrock Users: API Key Login <a class="header-anchor" href="#bedrock-users-api-key-login" aria-label="Permalink to “Bedrock Users: API Key Login”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>For users of Amazon Bedrock, you can now directly enter API Key during <code>opencode auth login</code>.</p><p>Previously only available through environment variables or AWS CLI configuration, now there&#39;s a more convenient option.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Experienced crash from configuration errors</td><td>✅ Upgrade</td></tr><tr><td>Used fork session feature</td><td>✅ Upgrade</td></tr><tr><td>Using desktop app</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',36),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Disable server mode unless explicitly enabled</li><li>Report specific errors on configuration errors instead of silent exit (@ariane-emory)</li><li>Upgrade OpenTUI to v0.1.72</li><li>Fix forked session losing parent-child message references after compaction (@ryanwyler)</li><li>Upgrade OpenTUI to v0.1.71, fix capability detection and Kitty keyboard support</li><li>Deduplicate same-name plugins by priority (@devxoul)</li><li>Upgrade Copilot plugin version</li><li>Fix model dialog search issue, prevent deprecated models from appearing in favorites/recent list</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Support API Key input during Bedrock login (@Raviguntakala)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Remove inline JavaScript</li><li>Remove custom URL parameters</li><li>Fix Zen mode new session model selector overflow (@0xajka)</li><li>Fully implement symlink support, enable PR CI (@jerome-benoit)</li><li>Each session independently stores terminal and review panel visibility</li><li>Terminal cursor changed to vertical bar, stops blinking when unfocused (@dbpolito)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><ul><li>@RD201: Add Scaleway provider to documentation</li><li>@dbpolito: Desktop terminal cursor optimization</li><li>@devxoul: Plugin deduplication mechanism</li><li>@jerome-benoit: Symlink support</li><li>@0xajka: Zen mode fix</li><li>@ryanwyler: Forked session fix</li><li>@Raviguntakala: Bedrock API Key login</li><li>@ariane-emory: Configuration error reporting</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(n,[["render",s]]);export{m as __pageData,g as default};
